ylabel('Reward', 'Interpreter', 'latex', 'FontSize', 14); %[output:50238aed]
% title('\textbf{DQN Agent Training Progress}', 'Interpreter', 'latex', 'FontSize', 16);
legend([hRaw, hAvg, hShade], {'Raw Episode Reward', 'Moving Average ($\mu$)', 'Deviation ($\mu \pm \sigma$)'}, ... %[output:group:247a839c] %[output:50238aed]
    'Location', 'best', 'Interpreter', 'latex', 'FontSize', 12); %[output:group:247a839c] %[output:50238aed]


%% Numerical summary
nEp = numel(epReward);
[bestR, bestEp] = max(epReward);
fprintf('\n=== Training summary ===\n'); %[output:1d845c3d]
fprintf('Episodes completed   : %d\n', nEp); %[output:0ef5338a]
fprintf('Total agent steps    : %d\n', totalAgentSteps(end)); %[output:6d22ec16]
fprintf('Final episode reward : %.3f\n', epReward(end)); %[output:6b7afcef]
fprintf('Final avg reward     : %.3f\n', epAvgReward(end)); %[output:26543863]
fprintf('Best episode reward  : %.3f (episode %d)\n', bestR, bestEp); %[output:1f7a319c]
