% figure;
% bar(1:EnvPars.T, Q_map_pos(:), 'FaceColor', [0.2 0.5 0.8]);
% xlabel('Action $t_\psi$', 'Interpreter', 'latex');
% ylabel('$\max_a Q(s, a)$', 'Interpreter', 'latex');
% title(sprintf('Q-function over positions | $\\psi_x$=%.2f, $\\psi_y$=%.2f', ...
